import{_ as e,o as a,c as o,ag as c}from"./chunks/framework.hRhVUe7m.js";const u=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/troubleshooting.md","filePath":"zh/guide/troubleshooting.md"}'),r={name:"zh/guide/troubleshooting.md"};function d(i,s,p,t,l,n){return a(),o("div",null,[...s[0]||(s[0]=[c('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><div class="lead-panel"><span class="kicker">管理侧排查</span><h1>先沿着运行时路径排查，再定位具体故障层</h1><p>MathClaw 的问题通常不是单独的前端故障，而是 workspace、配置解析、通道凭据或定时任务状态之间的某一层断开。按运行时连接顺序排查会快得多。</p></div><h2 id="常见问题类型" tabindex="-1">常见问题类型 <a class="header-anchor" href="#常见问题类型" aria-label="Permalink to &quot;常见问题类型&quot;">​</a></h2><div class="issue-grid"><div class="issue-card"><h3>控制台指向了错误配置</h3><p>确认 console 解析的是 <code>~/.mathclaw/config.json</code>，并在需要时显式传入 workspace。</p></div><div class="issue-card"><h3>图谱是空的或长时间不更新</h3><p>检查 session 写入、memory 生成和 graph JSON 更新时间，确认它们仍在同步。</p></div><div class="issue-card"><h3>心跳看起来停住了</h3><p>先看 <code>workspace/cron/jobs.json</code>，再比较页面刷新时间和最近一次成功总结时间。</p></div></div><h2 id="推荐排查顺序" tabindex="-1">推荐排查顺序 <a class="header-anchor" href="#推荐排查顺序" aria-label="Permalink to &quot;推荐排查顺序&quot;">​</a></h2><div class="steps-grid"><div class="step-card"><span class="flow-step">01</span><h3>先看运行状态</h3><p>确认 gateway、console、模型 provider 和通道数量仍然正常。</p></div><div class="step-card"><span class="flow-step">02</span><h3>再看心跳</h3><p>比较 next run、last run 和 recent result，判断是短时波动还是已经断档。</p></div><div class="step-card"><span class="flow-step">03</span><h3>检查 workspace 文件</h3><p>重点查看 <code>sessions/</code>、<code>memory/graphs/</code> 和 <code>cron/</code> 是否持续写入。</p></div><div class="step-card"><span class="flow-step">04</span><h3>定位到具体通道</h3><p>如果只有某一个入口异常，优先检查该通道的凭据和日志。</p></div></div><div class="highlight-panel"><h2>可移植启动提醒</h2><p>优先使用仓库相对路径，而不是机器专属绝对路径。这样 console、gateway 和文档更容易在不同机器之间保持一致。</p><ul><li>主配置路径：<code>~/.mathclaw/config.json</code></li><li>控制台启动：<code>cd console &amp;&amp; MATHCLAW_CONSOLE_WORKSPACE=../workspace python serve.py</code></li><li>关键图谱文件：<code>workspace/memory/graphs/knowledge_graph.json</code> 和 <code>workspace/memory/graphs/error_graph.json</code></li></ul></div>',7)])])}const v=e(r,[["render",d]]);export{u as __pageData,v as default};
